  ('elementary-f29af906-moex-00938', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法規定，下列有關申請使用許可審議之敘述，何者錯誤？', '["申請使用許可範圍屬農業發展地區者，由直轄市、縣（市）主管機關審議", "申請使用許可範圍屬城鄉發展地區者，由中央主管機關審議", "申請使用範圍跨二個直轄市、縣（市）行政區以上者，由中央主管機關審議", "申請使用範圍為填海造地案件者，由中央主管機關審議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00939', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法規定，從事未符合國土功能分區及其分類使用原則之一定規模以上或性質特殊之土地使用 者，由該管直轄市、縣（市）主管機關處行為人新臺幣多少之罰鍰？', '["6萬元以上30萬元以下", "30萬元以上150萬元以下", "100萬元以上500萬元以下", "500萬元以上1,000萬元以下"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00940', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '依國土計畫法規定，違反土地使用管制，若無法發現行為人時，直轄市、縣（市）主管機關應依序命其 他主體限期停止使用或恢復原狀。有關命令之對象，其順序為下列何者？', '["土地或地上物之使用人、管理人或所有人", "土地或地上物之所有人、使用人或管理人", "土地或地上物之管理人、使用人或所有人", "土地或地上物之所有人、管理人或使用人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00941', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '有關市地重劃地區選定後，地方政府得報經上級主管機關核定後，公告禁止或限制之事項，下列敘述何 者錯誤？', '["得禁止建築改良物之增建", "得禁止土地移轉", "得禁止土地分割及設定負擔", "禁止或限制之期間得延長一次"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00942', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '國土計畫法有關國土功能分區之種類，下列何者不包括在內？', '["農業發展地區", "國土復育地區", "國土保育地區", "海洋資源地區"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
  ('elementary-f29af906-moex-00943', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '下列關於都市更新條例所定都市更新之敘述，何者正確？', '["都市更新案申請建築執照之相關法規適用，一律以申請建築執照日為準", "核准都市更新事業概要前，主管機關應舉行聽證", "有關都市更新事業計畫之核定，在計畫核定前已無爭議者，主管機關得不舉行聽證", "於都市更新事業概要核准前，主管機關應舉行公聽會"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL),
