  ('elementary-f29af906-moex-00947', 'elementary-f29af906', 'elementary-f29af906-moex-110-20d8901b', 'sub-elementary-f29af906-04', NULL, 'single_choice', '外國人得依中華民國法律應不動產經紀人考試或參加營業員訓練。下列敘述，何者錯誤？', '["外國人請領不動產經紀人證書，應向居留地直轄市或縣（市）主管機關申請之", "外國人經許可在中華民國充任經紀人員者，其有關業務上所為之文件、圖說，應以中華民國文字為之", "應經直轄市、縣（市）政府許可，始得受僱於經紀業為經紀人員", "應遵守中華民國一切法令"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:56+00:00", "source_pdf_sha1": "753edbff8c70", "answer_pdf_sha1": "09eb751b23b0", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "514", "s": "0306", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "土地行政大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "地政"}'::jsonb, NULL)
